"""HTTP routes for catalog, invoke, and audit."""

from collections.abc import Callable
from datetime import UTC, datetime
from time import perf_counter
from typing import Any, get_args
from uuid import UUID, uuid4

from fastapi import APIRouter, Body, Header, HTTPException
from pydantic import BaseModel, ValidationError

from src.models import (
    FetchGdriveDocArgs,
    GetSlackMessagesArgs,
    Outcome,
    SearchPrsArgs,
    Brand,
    ToolDefinition,
    ToolInvocation,
    ToolInvokeResponse,
)
from src.permissions import (
    PermissionDecision,
    check_fetch_gdrive_doc,
    check_get_slack_messages,
    check_search_prs,
)
from src.store import add_invocation
from src.tools import fetch_gdrive_doc, get_slack_messages, list_tools, search_prs

router = APIRouter()
BRANDS = set(get_args(Brand))


class ToolSpec(BaseModel):
    """Internal registry entry for one invokable tool."""

    args_model: type[BaseModel]
    permission: Callable[[Brand, Any], PermissionDecision]
    execute: Callable[[Any], tuple[Any, str]]


TOOL_REGISTRY: dict[str, ToolSpec] = {
    "search_prs": ToolSpec(
        args_model=SearchPrsArgs,
        permission=check_search_prs,
        execute=search_prs,
    ),
    "get_slack_messages": ToolSpec(
        args_model=GetSlackMessagesArgs,
        permission=check_get_slack_messages,
        execute=get_slack_messages,
    ),
    "fetch_gdrive_doc": ToolSpec(
        args_model=FetchGdriveDocArgs,
        permission=check_fetch_gdrive_doc,
        execute=fetch_gdrive_doc,
    ),
}


@router.get("/tools")
def get_tools() -> list[ToolDefinition]:
    """Return the tool catalog."""
    return list_tools()


@router.post("/tools/search_prs/invoke")
def invoke_search_prs(
    payload: SearchPrsArgs,
    x_caller_brand: str = Header(alias="X-Caller-Brand"),
) -> ToolInvokeResponse:
    """Invoke PR search with an OpenAPI-visible request schema."""
    return invoke_registered_tool("search_prs", dump_args(payload), x_caller_brand)


@router.post("/tools/get_slack_messages/invoke")
def invoke_get_slack_messages(
    payload: GetSlackMessagesArgs,
    x_caller_brand: str = Header(alias="X-Caller-Brand"),
) -> ToolInvokeResponse:
    """Invoke Slack message lookup with an OpenAPI-visible request schema."""
    return invoke_registered_tool(
        "get_slack_messages",
        dump_args(payload),
        x_caller_brand,
    )


@router.post("/tools/fetch_gdrive_doc/invoke")
def invoke_fetch_gdrive_doc(
    payload: FetchGdriveDocArgs,
    x_caller_brand: str = Header(alias="X-Caller-Brand"),
) -> ToolInvokeResponse:
    """Invoke GDrive fetch with an OpenAPI-visible request schema."""
    return invoke_registered_tool(
        "fetch_gdrive_doc", dump_args(payload), x_caller_brand
    )


@router.post("/tools/{name}/invoke", include_in_schema=False)
def invoke_tool(
    name: str,
    payload: dict[str, Any] = Body(...),
    x_caller_brand: str = Header(alias="X-Caller-Brand"),
) -> ToolInvokeResponse:
    """Validate, authorize, execute, and audit one tool call."""
    return invoke_registered_tool(name, payload, x_caller_brand)


def invoke_registered_tool(
    name: str,
    payload: dict[str, Any],
    x_caller_brand: str,
) -> ToolInvokeResponse:
    """Validate, authorize, execute, and audit one registered tool call."""
    started_at = perf_counter()
    tool_call_id = uuid4()
    caller_brand = parse_caller_brand(x_caller_brand)
    spec = get_tool_spec(name)
    args = validate_args(spec, payload, tool_call_id, caller_brand, name, started_at)
    decision = spec.permission(caller_brand, args)
    if not decision.allowed:
        audit(
            tool_call_id,
            caller_brand,
            name,
            payload,
            "brand_denied",
            started_at,
            decision.denial_reason,
        )
        raise HTTPException(status_code=403, detail=decision.denial_reason)
    result, summary = spec.execute(args)
    audit(
        tool_call_id, caller_brand, name, payload, "success", started_at, None, summary
    )
    return ToolInvokeResponse(tool_call_id=tool_call_id, result=result)


def dump_args(args: BaseModel) -> dict[str, Any]:
    """Convert typed request args into JSON-compatible audit payload."""
    return args.model_dump(mode="json")


def parse_caller_brand(raw_brand: str) -> Brand:
    """Parse X-Caller-Brand into a supported brand."""
    if raw_brand in BRANDS:
        return raw_brand  # type: ignore[return-value]
    raise HTTPException(status_code=400, detail="invalid X-Caller-Brand")


def get_tool_spec(name: str) -> ToolSpec:
    """Find a tool registry entry or raise a 404."""
    spec = TOOL_REGISTRY.get(name)
    if spec is None:
        raise HTTPException(status_code=404, detail="unknown tool")
    return spec


def validate_args(
    spec: ToolSpec,
    payload: dict[str, Any],
    tool_call_id: UUID,
    caller_brand: Brand,
    tool_name: str,
    started_at: float,
) -> BaseModel:
    """Validate raw args and audit schema failures."""
    try:
        return spec.args_model.model_validate(payload)
    except ValidationError as exc:
        audit(
            tool_call_id,
            caller_brand,
            tool_name,
            payload,
            "schema_invalid",
            started_at,
            str(exc),
        )
        raise HTTPException(status_code=422, detail=exc.errors()) from exc


def audit(
    tool_call_id: UUID,
    caller_brand: Brand,
    tool_name: str,
    args: dict[str, Any],
    outcome: Outcome,
    started_at: float,
    denial_reason: str | None = None,
    result_summary: str | None = None,
) -> None:
    """Store a completed invocation audit event."""
    add_invocation(
        ToolInvocation(
            tool_call_id=tool_call_id,
            caller_brand=caller_brand,
            tool_name=tool_name,
            args=args,
            outcome=outcome,
            denial_reason=denial_reason,
            result_summary=result_summary,
            latency_ms=elapsed_ms(started_at),
            called_at=datetime.now(UTC),
        )
    )


def elapsed_ms(started_at: float) -> int:
    """Return elapsed milliseconds for a monotonic start time."""
    return int((perf_counter() - started_at) * 1000)

"""FastAPI entry point for the DH context injection server."""

from fastapi import FastAPI, Request
from fastapi.exceptions import RequestValidationError
from fastapi.responses import JSONResponse

from src.audit_routes import router as audit_router
from src.routes import router as tools_router

app = FastAPI(title="DH Context Injection Server")
app.include_router(tools_router)
app.include_router(audit_router)


@app.exception_handler(RequestValidationError)
def validation_exception_handler(
    request: Request,
    exc: RequestValidationError,
) -> JSONResponse:
    """Keep caller identity errors aligned with the documented error model."""
    del request
    if missing_caller_brand(exc):
        return JSONResponse(
            status_code=400,
            content={"detail": "invalid X-Caller-Brand"},
        )
    return JSONResponse(status_code=422, content={"detail": exc.errors()})


@app.get("/health")
def health() -> dict[str, str]:
    """Liveness probe."""
    return {"status": "ok"}


def missing_caller_brand(exc: RequestValidationError) -> bool:
    """Return whether validation failed because X-Caller-Brand is absent."""
    return any(
        error.get("type") == "missing"
        and error.get("loc") == ("header", "X-Caller-Brand")
        for error in exc.errors()
    )
